import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';

function Sidebar({ showSidebar, sidebarGender, setShowSidebar }) {
  const [perfumeItems, setPerfumeItems] = useState([]);

  const subCategoryItems = [
    'Top',
    'Bottoms',
    'Bag',
    'Accessories',
    'Shoes'
  ];

  // Fetch perfume products when sidebar opens for perfumery
  useEffect(() => {
    if (showSidebar && sidebarGender === 'PERFUMERY') {
      fetchPerfumes();
    }
  }, [showSidebar, sidebarGender]);

  const fetchPerfumes = async () => {
    try {
      const res = await axios.get('/api/products');
      const perfumes = res.data
        .filter(p => p.gender === 'PERFUMERY')
        .map(p => ({ name: p.name, id: p._id }));
      setPerfumeItems(perfumes);
    } catch (error) {
      console.error('Error fetching perfumes:', error);
    }
  };

  return (
    <>
      {/* Sliding Sidebar Overlay */}
      {showSidebar && (
        <div
          style={{
            position: 'fixed',
            top: 0,
            left: 0,
            width: '100%',
            height: '100%',
            backgroundColor: 'rgba(0, 0, 0, 0.5)',
            zIndex: 100,
            animation: 'fadeIn 0.3s ease'
          }}
          onClick={() => setShowSidebar(false)}
        />
      )}

      {/* Sidebar Panel */}
      <div
        style={{
          position: 'fixed',
          top: 0,
          left: 0,
          width: '320px',
          height: '100vh',
          backgroundColor: 'rgba(255, 255, 255, 0.95)',
          zIndex: 101,
          padding: '50px 40px',
          boxSizing: 'border-box',
          overflowY: 'auto',
          transform: showSidebar ? 'translateX(0)' : 'translateX(-100%)',
          transition: 'transform 0.4s ease',
          fontFamily: 'Helvetica, Arial, sans-serif'
        }}
      >
        {/* Close Button */}
        <button
          onClick={() => setShowSidebar(false)}
          style={{
            position: 'absolute',
            top: '30px',
            right: '30px',
            background: 'none',
            border: 'none',
            fontSize: '24px',
            color: '#000',
            cursor: 'pointer',
            padding: '0'
          }}
        >
          ×
        </button>

        {/* Sidebar Title - Just Gender Name */}
        <h2
          style={{
            fontSize: '16px',
            fontFamily: 'Helvetica, Arial, sans-serif',
            fontWeight: '400',
            letterSpacing: '0.5px',
            textTransform: 'uppercase',
            color: '#000',
            margin: '0 0 35px 0',
            lineHeight: '1.4'
          }}
        >
          {sidebarGender}
        </h2>

        {/* View All Button */}
        <Link
          to={`/${sidebarGender.toLowerCase()}`}
          onClick={() => setShowSidebar(false)}
          style={{
            fontSize: '13px',
            fontFamily: 'Helvetica, Arial, sans-serif',
            fontWeight: '300',
            letterSpacing: '0.3px',
            color: '#000',
            padding: '16px 0',
            cursor: 'pointer',
            borderBottom: '1px solid #e5e5e5',
            marginBottom: '30px',
            transition: 'color 0.3s',
            display: 'block',
            textDecoration: 'none'
          }}
          onMouseEnter={(e) => e.target.style.color = '#999'}
          onMouseLeave={(e) => e.target.style.color = '#000'}
        >
          View All
        </Link>

        {/* Subcategories or Perfume Items */}
        <div style={{ marginBottom: '40px' }}>
          {sidebarGender === 'PERFUMERY' ? (
            // Show Perfume Names
            perfumeItems.map((perfume) => (
              <Link
                key={perfume.id}
                to={`/product/${perfume.id}`}
                onClick={() => setShowSidebar(false)}
                style={{
                  fontSize: '13px',
                  fontFamily: 'Helvetica, Arial, sans-serif',
                  fontWeight: '300',
                  letterSpacing: '0.3px',
                  color: '#000',
                  padding: '16px 0',
                  cursor: 'pointer',
                  borderBottom: '1px solid #e5e5e5',
                  transition: 'color 0.3s',
                  display: 'block',
                  textDecoration: 'none'
                }}
                onMouseEnter={(e) => e.target.style.color = '#999'}
                onMouseLeave={(e) => e.target.style.color = '#000'}
              >
                {perfume.name}
              </Link>
            ))
          ) : (
            // Show Categories for Men/Women
            subCategoryItems.map((item) => (
              <Link
                key={item}
                to={`/${sidebarGender.toLowerCase()}?category=${item.toLowerCase()}`}
                onClick={() => setShowSidebar(false)}
                style={{
                  fontSize: '13px',
                  fontFamily: 'Helvetica, Arial, sans-serif',
                  fontWeight: '300',
                  letterSpacing: '0.3px',
                  color: '#000',
                  padding: '16px 0',
                  cursor: 'pointer',
                  borderBottom: '1px solid #e5e5e5',
                  transition: 'color 0.3s',
                  display: 'block',
                  textDecoration: 'none'
                }}
                onMouseEnter={(e) => e.target.style.color = '#999'}
                onMouseLeave={(e) => e.target.style.color = '#000'}
              >
                {item}
              </Link>
            ))
          )}
        </div>

        {/* Description at bottom */}
        <div
          style={{
            marginTop: 'auto',
            paddingTop: '40px',
            borderTop: '1px solid #e5e5e5',
            fontSize: '11px',
            fontWeight: '300',
            letterSpacing: '0.3px',
            color: '#999',
            lineHeight: '1.6'
          }}
        >
          Discover our latest premium {sidebarGender.toLowerCase()} collection crafted from the finest materials.
        </div>
      </div>
    </>
  );
}

export default Sidebar;
